/* Refresh Image Toolkit's popup footer without changing plugin behavior. */
body .oit-normal .oit-img-footer {
  position: fixed !important;
  left: 0 !important;
  right: 0 !important;
  bottom: calc(20px + env(safe-area-inset-bottom, 0px)) !important;
  display: flex !important;
  justify-content: center !important;
  align-items: center !important;
  pointer-events: none !important;
  text-align: center !important;
}

body .oit-normal .oit-img-footer .oit-img-title {
  display: none !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar {
  width: auto !important;
  max-width: calc(100vw - 32px) !important;
  height: auto !important;
  min-height: 44px !important;
  margin: 0 !important;
  padding: 6px 8px !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 2px !important;
  overflow-x: auto !important;
  list-style: none !important;
  white-space: nowrap !important;
  pointer-events: auto !important;
  border: 1px solid rgba(255, 255, 255, 0.16) !important;
  border-radius: 999px !important;
  background: rgba(20, 20, 22, 0.74) !important;
  box-shadow:
    0 14px 40px rgba(0, 0, 0, 0.34),
    0 2px 8px rgba(0, 0, 0, 0.2) !important;
  backdrop-filter: blur(16px) saturate(140%) !important;
  -webkit-backdrop-filter: blur(16px) saturate(140%) !important;
  scrollbar-width: none !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar::-webkit-scrollbar {
  display: none !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar:hover {
  border-radius: 999px !important;
  background: rgba(20, 20, 22, 0.82) !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar > li {
  position: relative !important;
  float: none !important;
  flex: 0 0 34px !important;
  width: 34px !important;
  height: 34px !important;
  margin: 0 !important;
  padding: 0 !important;
  display: inline-flex !important;
  align-items: center !important;
  justify-content: center !important;
  overflow: visible !important;
  border-radius: 8px !important;
  opacity: 0.88 !important;
  transition:
    background-color 120ms ease,
    opacity 120ms ease,
    transform 120ms ease !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar > li:hover {
  animation: none !important;
  background: rgba(255, 255, 255, 0.14) !important;
  opacity: 1 !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar > li:active {
  transform: scale(0.96) !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar > li::before {
  flex: 0 0 25px !important;
  opacity: 0.96 !important;
  filter: drop-shadow(0 1px 1px rgba(0, 0, 0, 0.35)) !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_zoom_out {
  order: 10 !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_zoom_to_100 {
  order: 11 !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_zoom_in {
  order: 12 !important;
  margin-right: 12px !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_full_screen {
  order: 20 !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_refresh {
  order: 21 !important;
  margin-right: 12px !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_rotate_left {
  order: 30 !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_rotate_right {
  order: 31 !important;
  margin-right: 12px !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_copy {
  order: 40 !important;
  margin-right: 12px !important;
  background: rgba(255, 255, 255, 0.1) !important;
  box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.12) !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_scale_x {
  order: 50 !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_scale_y {
  order: 51 !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_invert_color {
  order: 52 !important;
}

body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_zoom_in::after,
body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_refresh::after,
body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_rotate_right::after,
body .oit-normal .oit-img-footer .oit-img-toolbar .toolbar_copy::after {
  content: "";
  position: absolute;
  top: 8px;
  right: -7px;
  width: 1px;
  height: 18px;
  background: rgba(255, 255, 255, 0.18);
}

@media (max-width: 560px) {
  body .oit-normal .oit-img-footer {
    bottom: calc(12px + env(safe-area-inset-bottom, 0px)) !important;
  }

  body .oit-normal .oit-img-footer .oit-img-toolbar {
    max-width: calc(100vw - 20px) !important;
    padding: 5px 6px !important;
  }

  body .oit-normal .oit-img-footer .oit-img-toolbar > li {
    flex-basis: 32px !important;
    width: 32px !important;
    height: 32px !important;
  }
}

